const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const express = require('express');

const ALLOWED_HEADER_PREFIXES = ['x-', 'user-agent', 'authorization', 'content-type'];
const BLOCKED_HEADERS = new Set([
  'host',
  'connection',
  'keep-alive',
  'transfer-encoding',
  'upgrade',
  'te',
  'trailer',
  'proxy-authorization',
  'proxy-authenticate'
]);

const MAX_HEADER_SIZE = 8192;
const MAX_HEADER_COUNT = 100;
const MAX_METADATA_SIZE = 16384;

function sanitizeHeaderValue(value) {
  if (typeof value !== 'string') {
    return String(value);
  }
  
  const sanitized = value.replace(/[\r\n\0]/g, '');
  
  if (sanitized.length > MAX_HEADER_SIZE) {
    throw new Error('Header value exceeds maximum size');
  }
  
  return sanitized;
}

function sanitizeHeaderKey(key) {
  if (typeof key !== 'string') {
    return null;
  }
  
  const normalized = key.toLowerCase().trim();
  
  if (!/^[a-z0-9\-_.]+$/.test(normalized)) {
    return null;
  }
  
  if (normalized.startsWith('grpc-')) {
    return null;
  }
  
  return normalized;
}

function isHeaderAllowed(headerName) {
  const normalized = headerName.toLowerCase();
  
  if (BLOCKED_HEADERS.has(normalized)) {
    return false;
  }
  
  for (const prefix of ALLOWED_HEADER_PREFIXES) {
    if (normalized.startsWith(prefix) || normalized === prefix) {
      return true;
    }
  }
  
  return false;
}

function createGrpcMetadataFromHttpHeaders(httpHeaders) {
  const metadata = new grpc.Metadata();
  let headerCount = 0;
  let totalSize = 0;
  
  for (const [key, value] of Object.entries(httpHeaders)) {
    if (headerCount >= MAX_HEADER_COUNT) {
      throw new Error('Too many headers');
    }
    
    const sanitizedKey = sanitizeHeaderKey(key);
    if (!sanitizedKey) {
      continue;
    }
    
    if (!isHeaderAllowed(sanitizedKey)) {
      continue;
    }
    
    try {
      const values = Array.isArray(value) ? value : [value];
      
      for (const val of values) {
        const sanitizedValue = sanitizeHeaderValue(val);
        const entrySize = sanitizedKey.length + sanitizedValue.length;
        
        if (totalSize + entrySize > MAX_METADATA_SIZE) {
          throw new Error('Metadata size exceeds maximum allowed');
        }
        
        metadata.add(sanitizedKey, sanitizedValue);
        totalSize += entrySize;
        headerCount++;
      }
    } catch (err) {
      console.error(`Error processing header ${sanitizedKey}:`, err.message);
      continue;
    }
  }
  
  return metadata;
}

function createSecureGrpcClient(protoPath, serviceName, serverAddress, options = {}) {
  const packageDefinition = protoLoader.loadSync(protoPath, {
    keepCase: true,
    longs: String,
    enums: String,
    defaults: true,
    oneofs: true
  });
  
  const protoDescriptor = grpc.loadPackageDefinition(packageDefinition);
  
  const credentials = options.useTls 
    ? grpc.credentials.createSsl()
    : grpc.credentials.createInsecure();
  
  const clientOptions = {
    'grpc.max_receive_message_length': options.maxMessageSize || 4 * 1024 * 1024,
    'grpc.max_send_message_length': options.maxMessageSize || 4 * 1024 * 1024,
    'grpc.max_metadata_size': MAX_METADATA_SIZE,
    'grpc.keepalive_time_ms': 30000,
    'grpc.keepalive_timeout_ms': 10000,
    'grpc.http2.max_pings_without_data': 0,
    'grpc.keepalive_permit_without_calls': 1
  };
  
  const ServiceClient = serviceName.split('.').reduce((obj, key) => obj[key], protoDescriptor);
  
  return new ServiceClient(serverAddress, credentials, clientOptions);
}

function forwardHttpToGrpc(grpcClient, methodName, httpReq, httpRes) {
  const metadata = createGrpcMetadataFromHttpHeaders(httpReq.headers);
  
  if (httpReq.ip) {
    metadata.add('x-forwarded-for', sanitizeHeaderValue(httpReq.ip));
  }
  
  if (httpReq.get('x-real-ip')) {
    metadata.add('x-real-ip', sanitizeHeaderValue(httpReq.get('x-real-ip')));
  }
  
  const deadline = new Date();
  deadline.setSeconds(deadline.getSeconds() + 30);
  
  const callOptions = {
    deadline: deadline
  };
  
  grpcClient[methodName](httpReq.body, metadata, callOptions, (error, response) => {
    if (error) {
      console.error('gRPC call error:', error);
      
      const statusCode = error.code === grpc.status.UNAUTHENTICATED ? 401 :
                         error.code === grpc.status.PERMISSION_DENIED ? 403 :
                         error.code === grpc.status.NOT_FOUND ? 404 :
                         error.code === grpc.status.INVALID_ARGUMENT ? 400 :
                         error.code === grpc.status.DEADLINE_EXCEEDED ? 504 :
                         500;
      
      httpRes.status(statusCode).json({
        error: error.details || 'Internal server error',
        code: error.code
      });
      return;
    }
    
    httpRes.json(response);
  });
}

const app = express();
app.use(express.json({ limit: '1mb' }));

